//
import { renderDom } from '../mark/dom-render';
import { extendScaleParser } from '../parser/parser-utils';

class BaseView {
    constructor(spec) {
        this.spec = spec;
    }

    draw(element) {
        let markParser = this.encode;
        if (!markParser) {
            return;
        }

        let customParser = this.spec.parser;
        if (customParser) {
            markParser = extendScaleParser(markParser, customParser);
        }

        this.element = element;
        renderDom(markParser, element);
    }

    create() {
        let parser = this.constructor.parser;
        if (parser) {
            return (this.encode = parser(this.spec));
        }
    }
}

export { BaseView };
